class SecureHttpLogger {
  static final _logger = SecureLogger();

  /// Log an outgoing HTTP request with sensitive data redacted
  static void logRequest({
    required String method,
    required Uri url,
    Map<String, String>? headers,
    Object? body,
    String? requestId,
  }) {
    final sanitizedHeaders = _redactHeaders(headers ?? {});
    final sanitizedUrl = _redactUrl(url);

    _logger.info(
      'HTTP $method $sanitizedUrl',
      tag: 'HTTP',
      context: {
        if (requestId != null) 'requestId': requestId,
        'method': method,
        'url': sanitizedUrl,
        'headers': sanitizedHeaders,
        if (body != null) 'bodyType': body.runtimeType.toString(),
        // Log body size, NOT body content (may contain sensitive data)
        if (body is String) 'bodyLength': body.length,
        if (body is List<int>) 'bodyLength': body.length,
      },
    );
  }

  /// Log an HTTP response with sensitive data redacted
  static void logResponse({
    required String method,
    required Uri url,
    required int statusCode,
    Map<String, String>? headers,
    String? body,
    Duration? duration,
    String? requestId,
  }) {
    final sanitizedUrl = _redactUrl(url);
    final level = statusCode >= 500
        ? LogLevel.error
        : statusCode >= 400
            ? LogLevel.warning
            : LogLevel.info;

    _logger.log(
      level,
      'HTTP $statusCode $method $sanitizedUrl${duration != null ? ' (${duration.inMilliseconds}ms)' : ''}',
      tag: 'HTTP',
      context: {
        if (requestId != null) 'requestId': requestId,
        'statusCode': statusCode,
        'method': method,
        'url': sanitizedUrl,
        if (duration != null) 'durationMs': duration.inMilliseconds,
        if (body != null) 'bodyLength': body.length,
        // For error responses, include a truncated, redacted snippet
        if (statusCode >= 400 && body != null)
          'errorSnippet': SecureLogger()
              ._redactString(body.length > 200 ? '${body.substring(0, 200)}...' : body),
      },
    );
  }

  /// Redact sensitive headers (Authorization, Cookie, etc.)
  static Map<String, String> _redactHeaders(Map<String, String> headers) {
    const sensitiveHeaders = {
      'authorization',
      'cookie',
      'set-cookie',
      'x-api-key',
      'x-auth-token',
      'proxy-authorization',
    };

    return headers.map((key, value) {
      if (sensitiveHeaders.contains(key.toLowerCase())) {
        return MapEntry(key, '[REDACTED]');
      }
      return MapEntry(key, value);
    });
  }

  /// Redact sensitive query parameters from URLs
  static String _redactUrl(Uri url) {
    if (url.queryParameters.isEmpty) return url.toString();

    const sensitiveParams = {
      'token',
      'access_token',
      'refresh_token',
      'api_key',
      'apikey',
      'key',
      'secret',
      'password',
      'code',
      'session',
    };

    final redactedParams = url.queryParameters.map((key, value) {
      if (sensitiveParams.contains(key.toLowerCase())) {
        return MapEntry(key, '[REDACTED]');
      }
      return MapEntry(key, value);
    });

    return url.replace(queryParameters: redactedParams).toString();
  }
}

