class SecureDatabaseLogger {
  static final _logger = SecureLogger();

  static void logQuery({
    required String operation,
    required String table,
    Duration? duration,
    int? rowCount,
    Map<String, dynamic>? whereClause,
  }) {
    // Redact values in where clauses but keep column names
    final sanitizedWhere = whereClause != null
        ? whereClause.map((key, value) => MapEntry(key, _classifyValue(value)))
        : null;

    _logger.debug(
      'DB $operation on $table${duration != null ? ' (${duration.inMilliseconds}ms)' : ''}',
      tag: 'DB',
      context: {
        'operation': operation,
        'table': table,
        if (duration != null) 'durationMs': duration.inMilliseconds,
        if (rowCount != null) 'rowCount': rowCount,
        if (sanitizedWhere != null) 'where': sanitizedWhere,
      },
    );

    // Warn on slow queries
    if (duration != null && duration.inMilliseconds > 500) {
      _logger.warning(
        'Slow DB query: $operation on $table took ${duration.inMilliseconds}ms',
        tag: 'DB_PERF',
      );
    }
  }

  static void logError({
    required String operation,
    required String table,
    required Object error,
    StackTrace? stackTrace,
  }) {
    _logger.error(
      'DB error during $operation on $table',
      tag: 'DB',
      error: error,
      stackTrace: stackTrace,
    );
  }

  /// Replace actual values with type descriptors to avoid logging PII
  static String _classifyValue(dynamic value) {
    if (value == null) return '<null>';
    if (value is int) return '<int>';
    if (value is double) return '<double>';
    if (value is bool) return '<bool>';
    if (value is String) return '<string:${value.length}>';
    if (value is List) return '<list:${value.length}>';
    return '<${value.runtimeType}>';
  }
}

