class SecureAuthLogger {
  static final _logger = SecureLogger();

  static void logLoginAttempt({
    required String method, // 'email', 'google', 'apple', 'biometric', etc.
    String? userId, // Only log if non-PII identifier; otherwise omit
  }) {
    _logger.info(
      'Auth: Login attempt via $method',
      tag: 'AUTH',
      context: {
        'method': method,
        // Hash or omit the userId; never log email/phone as identifier
        if (userId != null) 'userIdHash': _hashIdentifier(userId),
      },
    );
  }

  static void logLoginSuccess({
    required String method,
    String? userId,
  }) {
    _logger.info(
      'Auth: Login successful via $method',
      tag: 'AUTH',
      context: {
        'method': method,
        if (userId != null) 'userIdHash': _hashIdentifier(userId),
      },
    );
  }

  static void logLoginFailure({
    required String method,
    required String reason, // 'invalid_credentials', 'account_locked', etc.
    // Do NOT accept or log the actual password or token
  }) {
    _logger.warning(
      'Auth: Login failed via $method - $reason',
      tag: 'AUTH',
      context: {
        'method': method,
        'reason': reason,
      },
    );
  }

  static void logTokenRefresh({required bool success}) {
    if (success) {
      _logger.debug('Auth: Token refreshed successfully', tag: 'AUTH');
    } else {
      _logger.warning('Auth: Token refresh failed', tag: 'AUTH');
    }
  }

  static void logLogout({String? reason}) {
    _logger.info(
      'Auth: User logged out${reason != null ? ' ($reason)' : ''}',
      tag: 'AUTH',
    );
  }

  static void logSessionExpired() {
    _logger.info('Auth: Session expired', tag: 'AUTH');
  }

  /// Create a short, non-reversible hash for correlation without exposing PII
  static String _hashIdentifier(String id) {
    // Simple hash for log correlation - NOT cryptographic, just for obfuscation
    // In production, use a proper HMAC with a server-side key
    var hash = 0;
    for (var i = 0; i < id.length; i++) {
      hash = ((hash << 5) - hash + id.codeUnitAt(i)) & 0xFFFFFFFF;
    }
    return 'usr_${hash.toRadixString(16).padLeft(8, '0')}';
  }
}

