class SecureInteractionLogger {
  static final _logger = SecureLogger();

  static void logScreenView(String screenName) {
    _logger.debug(
      'Screen: $screenName',
      tag: 'NAV',
    );
  }

  static void logButtonTap(String buttonId, {String? screen}) {
    _logger.debug(
      'Tap: $buttonId${screen != null ? ' on $screen' : ''}',
      tag: 'UI',
    );
  }

  static void logFormSubmission({
    required String formName,
    required bool success,
    // Do NOT accept form field values
    List<String>? fieldNames, // Only log which fields, not their values
  }) {
    _logger.info(
      'Form: $formName ${success ? 'submitted' : 'failed'}',
      tag: 'UI',
      context: {
        'form': formName,
        'success': success,
        if (fieldNames != null) 'fields': fieldNames,
      },
    );
  }

  static void logUserAction(String action, {Map<String, dynamic>? metadata}) {
    // Metadata is still redacted by SecureLogger
    _logger.debug(
      'Action: $action',
      tag: 'UI',
      context: metadata,
    );
  }

  static void logError({
    required String screen,
    required String action,
    required Object error,
    StackTrace? stackTrace,
  }) {
    _logger.error(
      'UI Error on $screen during $action',
      tag: 'UI',
      error: error,
      stackTrace: stackTrace,
    );
  }
}

