class AppHealthMonitor {
  static final _logger = SecureLogger();
  static final Stopwatch _appUptime = Stopwatch()..start();
  static int _errorCount = 0;
  static int _warningCount = 0;

  static void logAppStart() {
    _logger.info('App started', tag: 'HEALTH');
  }

  static void logAppResume() {
    _logger.debug('App resumed', tag: 'HEALTH');
  }

  static void logAppPause() {
    _logger.debug('App paused', tag: 'HEALTH');
  }

  static void logMemoryWarning() {
    _logger.warning('Memory warning received', tag: 'HEALTH');
  }

  static void logUnhandledError(Object error, StackTrace stackTrace) {
    _errorCount++;
    _logger.critical(
      'Unhandled error',
      tag: 'HEALTH',
      error: error,
      stackTrace: stackTrace,
      context: {
        'errorCount': _errorCount,
        'uptimeSeconds': _appUptime.elapsed.inSeconds,
      },
    );
  }

  static void logFlutterError(FlutterErrorDetails details) {
    _errorCount++;
    _logger.critical(
      'Flutter error: ${details.exceptionAsString()}',
      tag: 'HEALTH',
      context: {
        'library': details.library,
        'errorCount': _errorCount,
      },
    );
  }

  static Map<String, dynamic> getHealthSummary() {
    return {
      'uptimeSeconds': _appUptime.elapsed.inSeconds,
      'errorCount': _errorCount,
      'warningCount': _warningCount,
      'logBufferSize': SecureLogger().getRecentLogs().length,
    };
  }
}

// ---------------------------------------------------------------------------
// Example: Initialization in main.dart
// ---------------------------------------------------------------------------

/// Call this in your main() before runApp()
void initializeLogging() {
  final logger = SecureLogger();

  // In release mode, only log warnings and above
  if (kReleaseMode) {
    logger.setMinimumLevel(LogLevel.warning);
  }

  // Capture Flutter framework errors
  FlutterError.onError = (details) {
    AppHealthMonitor.logFlutterError(details);
  };

  AppHealthMonitor.logAppStart();
}

