void _exampleUsage() {
  final logger = SecureLogger();

  // ✅ SAFE: Logs operation type and timing, not data content
  logger.info('User profile loaded', tag: 'PROFILE', context: {
    'loadTimeMs': 142,
    'cached': false,
  });

  // ✅ SAFE: Sensitive fields are automatically redacted
  logger.debug('Config loaded', context: {
    'api_key': 'sk-1234567890', // Will be logged as [REDACTED]
    'region': 'us-east-1',
    'password': 'hunter2', // Will be logged as [REDACTED]
  });

  // ✅ SAFE: HTTP logging redacts auth headers and tokens
  SecureHttpLogger.logRequest(
    method: 'POST',
    url: Uri.parse('https://api.example.com/login?token=abc123'),
    headers: {
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiJ9.test.sig',
      'Content-Type': 'application/json',
    },
    requestId: 'req_001',
  );

  // ✅ SAFE: Auth logging never accepts passwords or tokens
  SecureAuthLogger.logLoginAttempt(method: 'email', userId: 'user@example.com');
  SecureAuthLogger.logLoginFailure(
    method: 'email',
    reason: 'invalid_credentials',
  );

  // ✅ SAFE: DB logging shows operation metadata, not row data
  SecureDatabaseLogger.logQuery(
    operation: 'SELECT',
    table: 'users',
    duration: const Duration(milliseconds: 45),
    rowCount: 1,
    whereClause: {'email': 'user@example.com'}, // Value replaced with <string:16>
  );

  // ✅ SAFE: UI logging captures actions, not input values
  SecureInteractionLogger.logFormSubmission(
    formName: 'login_form',
    success: true,
    fieldNames: ['email', 'password'], // Only field names, never values
  );
}